const express = require('express');
const session = require('express-session');
const twilio = require('twilio');

// Twilio account settings
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const client = new twilio(accountSid, authToken);

// Express app setup
const app = express();
app.use(session({
  secret: 'your_secret_key',
  resave: false,
  saveUninitialized: true
}));

let codes = {};

app.post('/login', (req, res) => {
  const username = req.body.username;
  const password = req.body.password;

  // Simulate user authentication logic here
  if (username === 'admin' && password === 'password') {
    const code = Math.floor(Math.random() * 900000) + 100000;
    codes[req.session.id] = code;
    sendSms(code, username);
    res.json({ message: 'Code sent successfully' });
  } else {
    res.status(401).json({ message: 'Invalid credentials' });
  }
});

app.post('/verify', (req, res) => {
  const code = req.body.code;

  if (codes[req.session.id] === parseInt(code)) {
    delete codes[req.session.id];
    res.json({ message: 'Code verified successfully' });
  } else {
    res.status(401).json({ message: 'Invalid code' });
  }
});

function sendSms(code, username) {
  const message = new twilio.messages.Message({
    from: '+1234567890',
    to: `+${username}`,
    body: `Your verification code is ${code}`
  });

  message.save((err, data) => {
    if (err) console.error(err);
  });
}

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});